#include <stdio.h>

int calculateMaxProfit(int *prices, int n) {
    if (n < 2) return 0;
    int minPrice = prices[0];
    int maxProfit = 0;
    for (int i = 1; i < n; ++i) {
        if (prices[i] < minPrice) {
            minPrice = prices[i];
        } else {
            int profit = prices[i] - minPrice;
            if (profit > maxProfit) maxProfit = profit;
        }
    }
    return maxProfit;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int prices[100000]; // sum of N over all test cases ≤ 100000
        for (int i = 0; i < N; ++i) scanf("%d", &prices[i]);
        printf("%d\n", calculateMaxProfit(prices, N));
    }
    return 0;
}

