#include <bits/stdc++.h>
using namespace std;

int calculateMaxProfit(const vector<int>& prices) {
    if (prices.size() < 2) return 0;
    int minPrice = prices[0];
    int maxProfit = 0;
    for (size_t i = 1; i < prices.size(); ++i) {
        if (prices[i] < minPrice) {
            minPrice = prices[i];
        } else {
            maxProfit = max(maxProfit, prices[i] - minPrice);
        }
    }
    return maxProfit;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if (!(cin >> T)) return 0;
    while (T--) {
        int N; cin >> N;
        vector<int> prices(N);
        for (int &x : prices) cin >> x;
        cout << calculateMaxProfit(prices) << '\n';
    }
    return 0;
}

