import sys

def calculateMaxProfit(prices):
    if len(prices) < 2:
        return 0
    min_price = prices[0]
    max_profit = 0
    for p in prices[1:]:
        if p < min_price:
            min_price = p
        else:
            profit = p - min_price
            if profit > max_profit:
                max_profit = profit
    return max_profit

def main():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        prices = [int(next(it)) for _ in range(N)]
        out.append(str(calculateMaxProfit(prices)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

